(75, 'home_split_description', 'Track payments, utilities, and maintenance requests with clear records and automated invoicing—so landlords and tenants always know what is due and what has been paid.', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(76, 'home_split_bullets_json', '[\r\n    {\r\n        \"title\": \"Accurate payment types\",\r\n        \"text\": \"Rent, utilities, and maintenance always recorded correctly.\"\r\n    },\r\n    {\r\n        \"title\": \"Automated invoicing\",\r\n        \"text\": \"Invoices update based on what was paid—no confusion.\"\r\n    },\r\n    {\r\n        \"title\": \"Tenant self-service\",\r\n        \"text\": \"Tenants can pay and track balances from the portal.\"\r\n    }\r\n]', '2026-02-11 07:35:22', '2026-02-11 07:57:07'),
(77, 'home_why_title', 'Why Choose RentSmart for Property Management?', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(78, 'home_why_subtitle', 'A modern, Kenyan-ready platform for landlords, managers, and agents—built for speed, clarity, and accurate records.', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(79, 'home_why_cards_json', '[\r\n    {\r\n        \"title\": \"M-PESA ready\",\r\n        \"text\": \"Accept payments and keep references organized for quick verification and reporting.\"\r\n    },\r\n    {\r\n        \"title\": \"Secure & reliable\",\r\n        \"text\": \"Keep your tenant and payment records safe with a cloud-ready setup and clear audit trails.\"\r\n    },\r\n    {\r\n        \"title\": \"Clear dashboards\",\r\n        \"text\": \"See what is due, what was paid, and what needs action—without digging through spreadsheets.\"\r\n    },\r\n    {\r\n        \"title\": \"Accurate invoicing\",\r\n        \"text\": \"Rent, utilities, and maintenance are tracked separately so invoices and balances remain correct.\"\r\n    }\r\n]', '2026-02-11 07:35:22', '2026-02-11 07:57:07'),
(80, 'home_features_title', 'Complete Property Management Software Features', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(81, 'home_features_subtitle', 'Streamline your rental business with our comprehensive property management tools designed for landlords and real estate professionals in Kenya', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(82, 'home_features_cards_json', '[\r\n    {\r\n        \"icon\": \"bi bi-house-door\",\r\n        \"title\": \"Property Management\",\r\n        \"text\": \"Manage unlimited properties, units, and tenants from one centralized dashboard. Track occupancy rates, rental income, and property performance in real-time.\"\r\n    },\r\n    {\r\n        \"icon\": \"bi bi-cash-coin\",\r\n        \"title\": \"Rent Collection & Tenant Portal\",\r\n        \"text\": \"Collect rent via M-PESA and give tenants self-service access to pay, view balances, and track payment history—anytime, anywhere.\"\r\n    },\r\n    {\r\n        \"icon\": \"bi bi-file-earmark-text\",\r\n        \"title\": \"Lease Management System\",\r\n        \"text\": \"Create digital lease agreements, track lease terms, and receive automated renewal reminders. Simplify tenant onboarding and documentation.\"\r\n    },\r\n    {\r\n        \"icon\": \"bi bi-graph-up\",\r\n        \"title\": \"Invoices & Financial Reports\",\r\n        \"text\": \"Generate invoices and receipts, and access clear reporting on income, expenses, and performance for confident decision-making.\"\r\n    },\r\n    {\r\n        \"icon\": \"bi bi-bell\",\r\n        \"title\": \"Automated Notifications\",\r\n        \"text\": \"Stay informed with automated SMS and email notifications for rent due dates, maintenance updates, lease renewals, and payment confirmations.\"\r\n    },\r\n    {\r\n        \"icon\": \"bi bi-lightning-charge\",\r\n        \"title\": \"Utilities Management\",\r\n        \"text\": \"Track metered and flat-rate utilities, readings, charges, and payments—so utilities are always clearly separated from rent.\"\r\n    },\r\n    {\r\n        \"icon\": \"bi bi-tools\",\r\n        \"title\": \"Maintenance Management\",\r\n        \"text\": \"Log requests, assign work, track progress, and record maintenance costs with clear references for invoices and statements.\"\r\n    },\r\n    {\r\n        \"icon\": \"bi bi-cash-stack\",\r\n        \"title\": \"Expense Tracking\",\r\n        \"text\": \"Record property expenses and keep a clear view of profitability with statements and reports by property and time period.\"\r\n    }\r\n]', '2026-02-11 07:35:22', '2026-02-11 07:57:07'),
(83, 'home_testimonials_title', 'Trusted by Property Managers Across Kenya', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(84, 'home_testimonials_subtitle', 'See how landlords and real estate professionals are transforming their property management with RentSmart', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(85, 'home_testimonials_json', '[\r\n    {\r\n        \"name\": \"Nancy Wanjiru\",\r\n        \"role\": \"Property Manager\",\r\n        \"text\": \"\\\"RentSmart has completely transformed how we manage our properties. The automated rent collection and reporting features save us hours every week.\\\"\"\r\n    },\r\n    {\r\n        \"name\": \"James Kamau\",\r\n        \"role\": \"Landlord\",\r\n        \"text\": \"\\\"The tenant portal has made communication so much easier. My tenants love being able to pay rent and submit maintenance requests online.\\\"\"\r\n    },\r\n    {\r\n        \"name\": \"David Kibara\",\r\n        \"role\": \"Real Estate Agent\",\r\n        \"text\": \"\\\"The financial reports and analytics help me make data-driven decisions. RentSmart has helped us increase our property portfolio\'s performance.\\\"\"\r\n    }\r\n]', '2026-02-11 07:35:22', '2026-02-12 08:17:43'),
(86, 'home_faq_title', 'Frequently Asked Questions', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(87, 'home_faq_subtitle', 'Everything you need to know about RentSmart property management software', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(88, 'home_faq_items_json', '[\r\n    {\r\n        \"q\": \"What is RentSmart property management software?\",\r\n        \"a\": \"RentSmart is a comprehensive cloud-based property management system designed for landlords, property managers, and real estate agents in Kenya. It helps you manage properties, tenants, rent collection, maintenance, utilities, and financial reporting all in one platform. With M-PESA integration and automated features, RentSmart simplifies rental property management.\"\r\n    },\r\n    {\r\n        \"q\": \"How long is the free trial period?\",\r\n        \"a\": \"RentSmart offers a generous 7-day free trial with full access to all features. No credit card required to start. You can explore all property management features, add properties and tenants, collect rent, and generate reports during the trial period. After 7-day, you can choose a plan that fits your needs.\"\r\n    },\r\n    {\r\n        \"q\": \"Does RentSmart integrate with M-PESA?\",\r\n        \"a\": \"Yes! RentSmart has full M-PESA integration for seamless rent collection. Tenants can pay rent directly through M-PESA, and payments are automatically recorded in the system. You\'ll receive instant notifications when payments are made, and the system automatically reconciles payments with tenant accounts.\"\r\n    },\r\n    {\r\n        \"q\": \"How many properties can I manage with RentSmart?\",\r\n        \"a\": \"The number of properties you can manage depends on your subscription plan. Our Basic plan supports up to 10 properties, Professional plan up to 50 properties, and Enterprise plan offers unlimited properties. Each property can have multiple units, and you can manage all of them from a single dashboard.\"\r\n    },\r\n    {\r\n        \"q\": \"Can tenants access the system?\",\r\n        \"a\": \"Yes! RentSmart includes a dedicated tenant portal where tenants can log in to view their lease details, make rent payments, submit maintenance requests, and access important documents. This self-service portal reduces your workload and improves tenant satisfaction.\"\r\n    }\r\n]', '2026-02-11 07:35:22', '2026-02-11 08:05:25'),
(89, 'home_cta_title', 'Transform Your Property Management Today', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(90, 'home_cta_description', 'Join hundreds of landlords and property managers in Kenya who are simplifying their rental business with RentSmart. Start your free trial now!', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(91, 'home_cta_button_text', 'Start Your 7-Day Free Trial', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(92, 'home_cta_footnote', 'No credit card required', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(93, 'contact_hero_title', 'Contact Sales & Support', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(94, 'contact_hero_subtitle', 'We\'d love to hear from you. Send us a message and we\'ll respond shortly.', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(95, 'terms_header', 'Terms of Service', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(96, 'privacy_header', 'Privacy Policy', '2026-02-11 07:35:22', '2026-02-11 07:35:22'),
(97, 'terms_body_html', '<p class=\"lead\">Last updated: February 11, 2026</p><h2>1. Acceptance of Terms</h2><p>By accessing and using RentSmart, you accept and agree to be bound by the terms and conditions of this agreement.</p><h2>2. Description of Service</h2><p>RentSmart provides property management software services including:</p><ul><li>Property and tenant management</li><li>Rent collection and payment processing</li><li>Financial reporting</li><li>Document management</li></ul><h2>3. User Accounts</h2><p>To use RentSmart, you must:</p><ul><li>Create an account with accurate information</li><li>Maintain the security of your account</li><li>Notify us of any unauthorized access</li><li>Be at least 18 years old</li></ul><h2>4. Subscription and Payments</h2><p>Our service is provided on a subscription basis:</p><ul><li>Subscription fees are billed monthly or annually</li><li>Payments are non-refundable</li><li>We may change pricing with 30 days notice</li><li>Free trial periods are available for new users</li></ul><h2>5. User Responsibilities</h2><p>You agree to:</p><ul><li>Comply with all applicable laws</li><li>Maintain accurate records</li><li>Protect tenant privacy</li><li>Use the service responsibly</li></ul><h2>6. Data Ownership</h2><p>You retain all rights to your data. We will:</p><ul><li>Protect your data security</li><li>Not access your data without permission</li><li>Delete your data upon account termination</li><li>Allow data export in standard formats</li></ul><h2>7. Service Availability</h2><p>While we strive for 99.9% uptime:</p><ul><li>We may perform scheduled maintenance</li><li>Service may be occasionally interrupted</li><li>We\'re not liable for downtime beyond our control</li></ul><h2>8. Termination</h2><p>We may terminate service if you:</p><ul><li>Violate these terms</li><li>Fail to pay subscription fees</li><li>Engage in fraudulent activity</li><li>Abuse the service</li></ul><h2>9. Contact Information</h2><p>For questions about these terms, contact us at:</p><ul><li>Email: rentsmart@timestentechnologies.co.ke</li><li>Phone: +254 795 155 230</li><li>Address: Nairobi, Kenya</li></ul>', '2026-02-11 08:29:47', '2026-02-11 09:00:56'),
(98, 'privacy_body_html', '<p class=\"lead\">Last updated: February 11, 2026</p><h2>1. Information We Collect</h2><p>We collect information that you provide directly to us, including:</p><ul><li>Name and contact information</li><li>Property management details</li><li>Payment information</li><li>Communication preferences</li></ul><h2>2. How We Use Your Information</h2><p>We use the information we collect to:</p><ul><li>Provide and maintain our services</li><li>Process your transactions</li><li>Send you important updates</li><li>Improve our services</li><li>Comply with legal obligations</li></ul><h2>3. Information Sharing</h2><p>We do not sell your personal information. We may share your information with:</p><ul><li>Service providers who assist in our operations</li><li>Legal authorities when required by law</li><li>Business partners with your consent</li></ul><h2>4. Data Security</h2><p>We implement appropriate security measures to protect your personal information, including:</p><ul><li>Encryption of sensitive data</li><li>Regular security assessments</li><li>Access controls and authentication</li><li>Secure data storage</li></ul><h2>5. Your Rights</h2><p>You have the right to:</p><ul><li>Access your personal information</li><li>Correct inaccurate data</li><li>Request deletion of your data</li><li>Opt-out of marketing communications</li></ul><h2>6. Contact Us</h2><p>If you have any questions about this Privacy Policy, please contact us at:</p><ul><li>Email: rentsmart@timestentechnologies.co.ke</li><li>Phone: +254 795 155 230</li><li>Address: Nairobi, Kenya</li></ul>', '2026-02-11 08:29:47', '2026-02-11 09:00:56'),
(99, 'contact_phone', '+254 795 155 230', '2026-02-11 08:29:47', '2026-02-11 08:29:47'),
(100, 'contact_email', 'rentsmart@timestentechnologies.co.ke', '2026-02-11 08:29:47', '2026-02-11 08:29:47'),
(101, 'contact_address', 'Nairobi, Kenya', '2026-02-11 08:29:47', '2026-02-11 08:29:47'),
(102, 'docs_hero_title', 'RentSmart Documentation', '2026-02-11 08:29:47', '2026-02-11 08:29:47'),
(103, 'docs_hero_subtitle', 'Comprehensive guide for landlords, property managers, agents, caretakers, tenants, and administrators.', '2026-02-11 08:29:47', '2026-02-11 08:29:47'),
(104, 'docs_body_html', '<section id=\"getting-started\"><h2>Getting Started</h2><p>Sign up for a free trial, configure your company profile, add properties and units, and invite team members.</p><ol><li>Register an account from the homepage.</li><li>Go to Settings → update Company name, logo, email, and phone.</li><li>Add Properties and Units; set rent amounts and occupancy details.</li><li>Add Tenants and create Leases for units.</li><li>Invite your team with role-specific permissions.</li></ol></section><hr><section id=\"user-roles\"><h2>User Roles & Permissions</h2><p>Assign roles to users to control access:</p><ul><li><strong>Admin:</strong> Full access to system features, reporting, user management.</li><li><strong>Landlord:</strong> Monitor properties, tenants, leases, payments, notices.</li><li><strong>Property Manager / Agent:</strong> Manage properties, leases, tenants, maintenance, and notices.</li><li><strong>Caretaker:</strong> Update unit status, submit maintenance updates.</li><li><strong>Tenant:</strong> Access lease details, make payments, submit maintenance requests, and view notices.</li></ul><p><em>Tip:</em> Use role-based permissions to maintain security and ensure accountability.</p></section><hr><section id=\"properties\"><h2>Properties & Units</h2><p>Manage property and unit details efficiently:</p><ul><li><strong>Properties:</strong> Create, edit, and upload documents or images for each property.</li><li><strong>Units:</strong> Add multiple units, assign rent, occupancy status, and link tenants via leases.</li><li>Track vacant and occupied units for better occupancy management.</li></ul><p><em>Tip:</em> Update unit details whenever tenants move in/out to keep records accurate.</p></section><hr><section id=\"tenants\"><h2>Tenants & Leases</h2><p>Create and manage tenants and their leases:</p><ul><li>Link active leases to units, setting rent, deposit, and lease duration.</li><li>Track tenant payment history, arrears, and lease expiry.</li><li>Generate reports for tenant balances and overdue payments.</li></ul></section><hr><section id=\"payments\"><h2>Payments & Invoices</h2><p>Track all payments and generate invoices:</p><ul><li>Record rent and utility payments (supports M-PESA manual logs).</li><li>Create invoices with multiple line items, apply tax, and post to ledger.</li><li>Download or email invoices in PDF format to tenants.</li><li>Automatic ledger posting ensures accounting consistency.</li></ul><p><em>Tip:</em> Reconcile payments weekly to avoid discrepancies.</p></section><hr><section id=\"maintenance\"><h2>Maintenance</h2><p>Track maintenance requests and costs:</p><ul><li>Tenants or caretakers can submit requests via the system.</li><li>Record actual maintenance cost; optionally deduct from tenant rent balance.</li><li>Track maintenance status and completion dates for reporting.</li></ul></section><hr><section id=\"utilities\"><h2>Utilities</h2><p>Manage utilities efficiently:</p><ul><li>Add metered or flat utilities per unit.</li><li>Record readings or monthly charges.</li><li>Include utilities in tenant invoices for accurate billing.</li></ul></section><hr><section id=\"messaging\"><h2>Messaging</h2><p>Communicate securely within RentSmart:</p><ul><li>Chat with tenants, managers, caretakers, and admins in real-time.</li><li>Broadcast notices or individual messages.</li><li>Keep all communication centralized for auditing and tracking.</li></ul></section><hr><section id=\"notices\"><h2>Notices</h2><p>Broadcast or schedule notices to tenants and staff:</p><ul><li>Send notices by property, unit, or individual tenant.</li><li>Schedule future notifications for rent reminders or announcements.</li><li>Track which tenants have read the notices.</li></ul></section><hr><section id=\"accounting\"><h2>Accounting</h2><p>Comprehensive accounting module:</p><ul><li>Chart of Accounts, General Ledger, Trial Balance.</li><li>Profit & Loss, Balance Sheet reporting.</li><li>Invoices automatically post to accounts receivable/revenue.</li></ul></section><hr><section id=\"esign\"><h2>E‑Signatures</h2><p>Digitally sign documents securely:</p><ul><li>Create signature requests for tenants, managers, or staff.</li><li>Share public links for document signing.</li><li>Track signature status and download signed documents.</li></ul></section><hr><section id=\"tenant-portal\"><h2>Tenant Portal</h2><p>Tenant self-service portal:</p><ul><li>View active lease, rent due, and payment history.</li><li>Submit maintenance requests and track progress.</li><li>Receive notices and communicate with property managers.</li></ul></section><hr><section id=\"reports\"><h2>Reports & Analytics</h2><p>Generate detailed reports for operational insights:</p><ul><li>Occupancy & vacancy reports per property/unit.</li><li>Tenant payment history & arrears.</li><li>Maintenance cost and completion analytics.</li><li>Revenue, Profit & Loss, Trial Balance, Balance Sheet.</li><li>Export reports in PDF, Excel, or CSV format.</li></ul></section><hr><section id=\"notifications\"><h2>Notifications & Alerts</h2><p>Automated alerts for timely actions:</p><ul><li>Upcoming rent due notifications for tenants.</li><li>Lease expiry alerts for managers and landlords.</li><li>Maintenance updates and completion notifications.</li><li>System alerts for unpaid balances or failed payments.</li></ul></section><hr><section id=\"mobile-access\"><h2>Mobile & Accessibility</h2><p>RentSmart is fully responsive and mobile-friendly:</p><ul><li>Access all core features on tablets and smartphones.</li><li>Tenants can pay rent and submit requests on the go.</li><li>Receive push notifications for alerts and updates.</li></ul></section><hr><section id=\"tips-best-practices\"><h2>Tips & Best Practices</h2><ul><li>Update property and unit details regularly for accurate records.</li><li>Use scheduled maintenance tracking to prevent overdue repairs.</li><li>Reconcile payments weekly to avoid accounting errors.</li><li>Encourage tenants to use the portal for payments and requests.</li><li>Regularly back up system data and maintain user role security.</li></ul></section><hr><section id=\"faq\"><h2>FAQ & Support</h2><p>For questions or help, contact:</p><ul><li>Email: <a href=\"mailto:rentsmart@timestentechnologies.co.ke\">rentsmart@timestentechnologies.co.ke</a></li><li>Phone: +254 795 155 230</li><li>In-app Messaging for real-time support</li><li>Visit the Contact page for additional resources.</li></ul></section>', '2026-02-11 08:29:47', '2026-02-11 08:29:47'),
