INSERT INTO `subscription_plans` (`id`, `name`, `price`, `description`, `features`, `created_at`, `updated_at`, `property_limit`, `unit_limit`, `listing_limit`) VALUES
(1, 'Starter', 3500.00, 'For individual landlords managing a small portfolio replacing spreadsheets.', 'Property & unit profiles with occupancy tracking\r\nTenant profiles & lease details\r\nManual rent tracking, arrears & rent summaries\r\nMaintenance request logging & status tracking\r\nAssign caretaker per property\r\nStaff records (caretaker, gardener, fundi, cleaner)\r\nStaff payment records\r\nBasic property expense tracking\r\nTenant portal (rent balance & statements)\r\nDocument upload (leases, agreements)\r\nEmail support ', '2025-06-28 18:01:30', '2026-02-19 06:50:25', 5, 100, 100),
(2, 'Professional', 7000.00, 'For growing property management businesses', 'Everything in Starter\r\nPartial & advance payment handling\r\nReal-time arrears tracking\r\nSMS & email rent reminders\r\nPayment confirmation notifications\r\nTenant portal with statements & balances\r\nMaintenance requests with task assignment & follow-ups\r\nProperty-level expense tracking\r\nMonthly income & financial reports\r\nImport and Export reports to Excel & PDF\r\nPriority email support', '2025-06-28 18:01:30', '2026-02-19 06:50:46', 20, 350, 350),
(3, 'Premium', 15000.00, 'Complete solution for large property managers', 'Everything in Professional\r\nBulk property & tenant actions\r\nAdvanced vacancy & unit analytics\r\nExpense tracking with net income reports\r\nCustom date-range financial reporting\r\nAdvanced maintenance & task tracking\r\nStaff management & staff payment control\r\nBulk SMS & email messaging\r\nActivity logs & audit trails\r\nAccounting-ready exports (Excel, CSV, PDF)\r\nPriority Email & WhatsApp support\r\nAssisted onboarding', '2025-06-28 18:01:30', '2026-02-19 06:50:59', 50, 800, 800),
(4, 'Enterprise', 50000.00, 'Large portfolios, real estate firms & institutional landlords.', '50+ properties with unlimited scale\r\nHigh-volume tenants & transactions\r\nCustom workflows & automation\r\nAPI access & system integrations\r\nCustom reports & dashboards\r\nAdvanced staff & payroll management\r\nDedicated account manager\r\nSLA & uptime guarantees\r\nDedicated onboarding & training\r\nPriority support & escalation\r\nBest for: Large portfolios, real estate firms & institutional landlords.', '2025-06-28 18:01:30', '2026-02-05 17:48:11', NULL, NULL, NULL);
